import{_ as n,o as t,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"Kho","description":"","frontmatter":{"title":"Kho"},"headers":[],"relativePath":"stock.md","filePath":"stock.md"}'),o={name:"stock.md"};function e(l,h,r,c,u,g){return t(),a("div",null,[...h[0]||(h[0]=[i('<h1 id="kho" tabindex="-1">Kho <a class="header-anchor" href="#kho" aria-label="Permalink to &quot;Kho&quot;">​</a></h1><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Quản lý tồn kho là cốt lõi của mọi doanh nghiệp sản xuất và thương mại. Mô-đun Kho (Stock) trong ABNERP cung cấp các công cụ toàn diện để theo dõi, kiểm soát và tối ưu hóa hàng tồn kho theo thời gian thực. Từ nhập xuất hàng ngày đến kiểm kê cuối kỳ, hệ thống đảm bảo tính chính xác và minh bạch của mọi giao dịch kho.</p><h2 id="cac-giao-dich-chinh" tabindex="-1">Các giao dịch chính <a class="header-anchor" href="#cac-giao-dich-chinh" aria-label="Permalink to &quot;Các giao dịch chính&quot;">​</a></h2><h3 id="_1-nhap-kho-stock-entry-—-material-receipt" tabindex="-1">1. Nhập kho (Stock Entry — Material Receipt) <a class="header-anchor" href="#_1-nhap-kho-stock-entry-—-material-receipt" aria-label="Permalink to &quot;1. Nhập kho (Stock Entry — Material Receipt)&quot;">​</a></h3><p>Ghi nhận hàng hóa, nguyên vật liệu đi vào kho:</p><ul><li>Mua hàng từ nhà cung cấp</li><li>Nhập kho thành phẩm từ sản xuất</li><li>Nhập kho trả lại từ khách hàng</li><li>Nhập kho điều chỉnh tăng</li></ul><h3 id="_2-xuat-kho-stock-entry-—-material-issue" tabindex="-1">2. Xuất kho (Stock Entry — Material Issue) <a class="header-anchor" href="#_2-xuat-kho-stock-entry-—-material-issue" aria-label="Permalink to &quot;2. Xuất kho (Stock Entry — Material Issue)&quot;">​</a></h3><p>Ghi nhận hàng hóa, nguyên vật liệu đi ra khỏi kho:</p><ul><li>Xuất nguyên vật liệu cho sản xuất</li><li>Xuất bán cho khách hàng</li><li>Xuất trả lại nhà cung cấp</li><li>Xuất hủy, xuất điều chỉnh giảm</li></ul><h3 id="_3-chuyen-kho-stock-entry-—-material-transfer" tabindex="-1">3. Chuyển kho (Stock Entry — Material Transfer) <a class="header-anchor" href="#_3-chuyen-kho-stock-entry-—-material-transfer" aria-label="Permalink to &quot;3. Chuyển kho (Stock Entry — Material Transfer)&quot;">​</a></h3><p>Chuyển hàng giữa các kho hoặc giữa các vị trí trong cùng một kho:</p><ul><li>Chuyển kho nội bộ</li><li>Chuyển hàng đến điểm bán lẻ</li><li>Chuyển hàng giữa các chi nhánh</li></ul><h3 id="_4-kiem-ke-stock-reconciliation" tabindex="-1">4. Kiểm kê (Stock Reconciliation) <a class="header-anchor" href="#_4-kiem-ke-stock-reconciliation" aria-label="Permalink to &quot;4. Kiểm kê (Stock Reconciliation)&quot;">​</a></h3><p>Kiểm kê giúp đối chiếu số lượng hàng tồn kho thực tế với số liệu trên hệ thống:</p><ul><li><strong>Kiểm kê định kỳ</strong>: Cuối tháng/quý/năm</li><li><strong>Kiểm kê luân chuyển</strong>: Kiểm tra từng nhóm hàng theo lịch</li><li>Điều chỉnh chênh lệch tồn kho sau kiểm kê</li></ul><h2 id="cac-chu-đe-lien-quan" tabindex="-1">Các chủ đề liên quan <a class="header-anchor" href="#cac-chu-đe-lien-quan" aria-label="Permalink to &quot;Các chủ đề liên quan&quot;">​</a></h2><h3 id="thiet-lap-kho" tabindex="-1">Thiết lập Kho <a class="header-anchor" href="#thiet-lap-kho" aria-label="Permalink to &quot;Thiết lập Kho&quot;">​</a></h3><p>Cấu hình các tham số mặc định cho toàn bộ mô-đun Kho như phương pháp tính giá xuất kho (FIFO, bình quân gia quyền), đơn vị tính mặc định, kiểm tra tồn kho âm, v.v. Xem chi tiết tại <a href="/abnerp/stock-settings.html">Thiết lập Kho</a>.</p><h3 id="kho-hang" tabindex="-1">Kho hàng <a class="header-anchor" href="#kho-hang" aria-label="Permalink to &quot;Kho hàng&quot;">​</a></h3><p>Danh sách các kho hàng trong doanh nghiệp. Mỗi kho có thể được phân loại theo:</p><ul><li><strong>Loại kho</strong>: Kho chính, kho trung chuyển, kho điểm bán</li><li><strong>Địa điểm</strong>: Kho A, kho B, kho C</li><li><strong>Trạng thái</strong>: Đang hoạt động, tạm ngừng</li></ul><p>Xem thêm tại <a href="/abnerp/warehouse.html">Kho hàng</a>.</p><h3 id="mat-hang" tabindex="-1">Mặt hàng <a class="header-anchor" href="#mat-hang" aria-label="Permalink to &quot;Mặt hàng&quot;">​</a></h3><p>Danh mục tất cả hàng hóa, nguyên vật liệu, thành phẩm, dịch vụ. Mỗi mặt hàng có thể được quản lý với:</p><ul><li>Mã hàng, tên hàng, mô tả</li><li>Đơn vị tính cơ bản và các đơn vị tính thay thế</li><li>Giá nhập, giá bán, tồn kho tối thiểu/tối đa</li><li>Hình ảnh, mã vạch, thuế suất</li><li>Tài khoản kế toán mặc định (tồn kho, doanh thu, chi phí)</li></ul><h3 id="nhom-mat-hang" tabindex="-1">Nhóm mặt hàng <a class="header-anchor" href="#nhom-mat-hang" aria-label="Permalink to &quot;Nhóm mặt hàng&quot;">​</a></h3><p>Phân nhóm mặt hàng theo chủng loại để thuận tiện trong quản lý và báo cáo:</p><ul><li>Ví dụ: Điện tử, Thời trang, Thực phẩm, Văn phòng phẩm</li><li>Mỗi nhóm có thể có thuế suất, tài khoản kế toán mặc định riêng</li></ul><h3 id="đon-vi-tinh-uom" tabindex="-1">Đơn vị tính (UOM) <a class="header-anchor" href="#đon-vi-tinh-uom" aria-label="Permalink to &quot;Đơn vị tính (UOM)&quot;">​</a></h3><p>Quản lý các đơn vị tính và tỷ lệ quy đổi giữa chúng:</p><ul><li>Cái, hộp, thùng, kg, mét, lít</li><li>Chuyển đổi giữa các đơn vị: 1 thùng = 12 cái</li><li>Đơn vị tính cơ bản và đơn vị tính báo cáo</li></ul><h3 id="lo-va-serial-number" tabindex="-1">Lô và Serial Number <a class="header-anchor" href="#lo-va-serial-number" aria-label="Permalink to &quot;Lô và Serial Number&quot;">​</a></h3><ul><li><strong>Quản lý theo lô</strong>: Theo dõi hàng hóa theo lô sản xuất, hạn sử dụng</li><li><strong>Serial Number</strong>: Quản lý từng đơn vị sản phẩm riêng lẻ (IMSI, số khung, số máy)</li></ul><h2 id="video-huong-dan" tabindex="-1">Video hướng dẫn <a class="header-anchor" href="#video-huong-dan" aria-label="Permalink to &quot;Video hướng dẫn&quot;">​</a></h2><ul><li><a href="https://www.youtube.com/watch?v=example5" target="_blank" rel="noreferrer">Quản lý kho trên ABNERP</a></li><li><a href="https://www.youtube.com/watch?v=example6" target="_blank" rel="noreferrer">Hướng dẫn nhập xuất kho</a></li><li><a href="https://www.youtube.com/watch?v=example7" target="_blank" rel="noreferrer">Kiểm kê và điều chỉnh tồn kho</a></li><li><a href="https://www.youtube.com/watch?v=example8" target="_blank" rel="noreferrer">Quản lý lô và serial number</a></li></ul>',36)])])}const m=n(o,[["render",e]]);export{s as __pageData,m as default};
